import { Effect, Fiber, Console, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly status: number }> {}
class CacheMiss extends Data.TaggedError("CacheMiss")<{ readonly key: string }> {}

declare const fetchUser: (id: string) => Effect.Effect<string, HttpError>;
declare const readCache: (id: string) => Effect.Effect<string, CacheMiss>;

// raceWith lets us observe BOTH completions — whichever wins first, we explicitly
// interrupt the loser fiber and log the branch that produced the value.
export const getUser = (
  id: string,
): Effect.Effect<string, HttpError | CacheMiss> =>
  Effect.raceWith(fetchUser(id), readCache(id), {
    onSelfDone: (exit, loser) =>
      Effect.flatMap(Fiber.interrupt(loser), () =>
        Effect.flatMap(Console.log("primary won"), () => exit),
      ),
    onOtherDone: (exit, loser) =>
      Effect.flatMap(Fiber.interrupt(loser), () =>
        Effect.flatMap(Console.log("cache won"), () => exit),
      ),
  });
