import { Effect, Fiber, Console } from "effect";

declare const a: Effect.Effect<number>;
declare const b: Effect.Effect<number>;

// raceWith exposes both sides; interrupt the loser AND fire a compensating log.
export const raced: Effect.Effect<number> = Effect.raceWith(a, b, {
  onSelfDone: (selfExit, other) =>
    Effect.flatMap(Console.log("a won, compensating b"), () =>
      Effect.flatMap(Fiber.interrupt(other), () => selfExit),
    ),
  onOtherDone: (otherExit, self) =>
    Effect.flatMap(Console.log("b won, compensating a"), () =>
      Effect.flatMap(Fiber.interrupt(self), () => otherExit),
    ),
});
```

Effect.race picks the first winner and silently interrupts the loser, discarding its exit. Effect.raceWith gives you BOTH completions so you can run custom logic per side — log metrics, release resources, or transform the exit before returning. The loser is NOT auto-interrupted, so you must call Fiber.interrupt inside your finisher.

```typescript
import { Effect, Fiber, Exit, Console } from "effect";

declare const primary: Effect.Effect<string, Error>;
declare const fallback: Effect.Effect<string, Error>;

export const raced: Effect.Effect<string, Error> = Effect.raceWith(
  primary,
  fallback,
  {
    onSelfDone: (exit, loser) =>
      Effect.flatMap(Fiber.interrupt(loser), () =>
        Exit.isSuccess(exit)
          ? Effect.flatMap(Console.log("primary hit"), () => exit)
          : exit,
      ),
    onOtherDone: (exit, loser) =>
      Effect.flatMap(Fiber.interrupt(loser), () =>
        Exit.isSuccess(exit)
          ? Effect.flatMap(Console.log("fallback hit"), () => exit)
          : exit,
      ),
  },
);
