import { Effect, Fiber, Exit } from "effect";

// Both branches: interrupt the still-running sibling, then return the exit
// exactly as it came — success or failure is preserved in the E channel.
export const raceWithMetrics = <A, E, B, F>(
  a: Effect.Effect<A, E>,
  b: Effect.Effect<B, F>,
): Effect.Effect<A | B, E | F> =>
  Effect.raceWith(a, b, {
    onSelfDone: (exit, loser): Effect.Effect<A, E> =>
      Effect.flatMap(Fiber.interrupt(loser), () => exit),
    onOtherDone: (exit, loser): Effect.Effect<B, F> =>
      Effect.flatMap(Fiber.interrupt(loser), () => exit),
  }) as Effect.Effect<A | B, E | F>;

// Exit helpers remain available to callers if they want to branch on success.
export const _exitSampleOk = Exit.succeed(1);
