import { Effect, Fiber, Exit } from "effect";

// If the first completer succeeds, interrupt the loser and return the value.
// If the first completer fails, join the loser and return its exit instead.
export const raceFirstSuccess = <A, E>(
  a: Effect.Effect<A, E>,
  b: Effect.Effect<A, E>,
): Effect.Effect<A, E> =>
  Effect.raceWith(a, b, {
    onSelfDone: (exit, loser) =>
      Exit.isSuccess(exit)
        ? Effect.flatMap(Fiber.interrupt(loser), () => exit)
        : Fiber.join(loser),
    onOtherDone: (exit, loser) =>
      Exit.isSuccess(exit)
        ? Effect.flatMap(Fiber.interrupt(loser), () => exit)
        : Fiber.join(loser),
  });
