import { Effect } from "effect";

interface SignUp { readonly name: string; readonly email: string; readonly age: number }

type Field = { readonly key: string; readonly ok: true };
const field = (key: string): Field => ({ key, ok: true });

const validateName = (s: SignUp): Effect.Effect<Field, string> =>
  s.name.length >= 2 ? Effect.succeed(field("name")) : Effect.fail("name too short");
const validateEmail = (s: SignUp): Effect.Effect<Field, string> =>
  s.email.includes("@") ? Effect.succeed(field("email")) : Effect.fail("invalid email");
const validateAge = (s: SignUp): Effect.Effect<Field, string> =>
  s.age >= 18 ? Effect.succeed(field("age")) : Effect.fail("must be 18+");

// validateAll collects successes; if ANY fail the whole thing fails with a
// non-empty array of every error — never short-circuits.
export const validateSignUp = (
  s: SignUp,
): Effect.Effect<ReadonlyArray<Field>, ReadonlyArray<string>> =>
  Effect.validateAll([validateName, validateEmail, validateAge], (f) => f(s));
