```typescript
import { Effect } from "effect";

const v1 = (n: number): Effect.Effect<number, string> =>
  n > 0 ? Effect.succeed(n) : Effect.fail("negative");
const v2 = (n: number): Effect.Effect<number, string> =>
  n < 100 ? Effect.succeed(n) : Effect.fail("too big");
const v3 = (n: number): Effect.Effect<number, string> =>
  n % 2 === 0 ? Effect.succeed(n) : Effect.fail("odd");

// Effect.validateAll + concurrency: "unbounded" runs them in parallel and
// accumulates every failure into a ReadonlyArray<string>.
export const validate = (
  n: number,
): Effect.Effect<ReadonlyArray<number>, ReadonlyArray<string>> =>
  Effect.validateAll([v1, v2, v3], (f) => f(n), { concurrency: "unbounded" });
```

A monadic Either chain short-circuits at the first Left — the second and third validators never run, and the user only sees one of three problems. Applicative validation runs every validator independently and combines all Lefts into a NonEmptyArray via a Semigroup. The trade-off: because the branches can't depend on each other, validators must be independent.

```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as A from "fp-ts/Apply";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";

const V = E.getApplicativeValidation(RNEA.getSemigroup<string>());
const fail = (msg: string): E.Either<RNEA.ReadonlyNonEmptyArray<string>, never> =>
  E.left([msg] as const);

const checkName = (n: string) =>
  n.length >= 2 ? E.right(n) : fail("name too short");
const checkEmail = (e: string) =>
  e.includes("@") ? E.right(e) : fail("invalid email");
const checkAge = (a: number) =>
  a >= 18 ? E.right(a) : fail("must be 18+");

export const validate = (n: string, e: string, a: number) =>
  pipe(
    A.sequenceT(V)(checkName(n), checkEmail(e), checkAge(a)),
    E.map(([name, email, age]) => ({ name, email, age })),
  );
```

