import { Effect, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly url: string }> {}

declare const fetchUrl: (url: string) => Effect.Effect<string, FetchError>;

// Semaphore.withPermits(1) wraps each task so at most 4 run concurrently;
// Effect.forEach with `concurrency: "unbounded"` lets the semaphore be the gate.
export const processUrls = (urls: ReadonlyArray<string>) =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(4);
    return yield* Effect.forEach(
      urls,
      (url) => sem.withPermits(1)(fetchUrl(url)),
      { concurrency: "unbounded" },
    );
  });
