import { Effect } from "effect";

declare const work: (n: number) => Effect.Effect<number>;

// Approach 1: numeric concurrency on forEach is simplest when the limit is static.
export const withForEachCap = (items: ReadonlyArray<number>) =>
  Effect.forEach(items, work, { concurrency: 3 });

// Approach 2: a Semaphore gives you a shared limit across multiple forEach
// calls or across sibling effects.
export const withSemaphore = (items: ReadonlyArray<number>) =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(3);
    return yield* Effect.forEach(
      items,
      (i) => sem.withPermits(1)(work(i)),
      { concurrency: "unbounded" },
    );
  });
```

Effect.forEach's `concurrency: 3` option caps *that one loop* at three in-flight effects. If two independent loops each set the cap to 3, the system can have six concurrent tasks against the same downstream — exceeding the budget. A single Semaphore constructed OUTSIDE both loops is a shared permit pool: however many loops acquire from it, the total in-flight never exceeds the permit count.

