import { Effect, Queue } from "effect";

interface Job { readonly id: string; readonly payload: string }
declare const handle: (j: Job) => Effect.Effect<void>;

// Bulkhead: the bounded Queue provides back-pressure on producers, and the
// Semaphore caps concurrent handler execution even if workers grab faster.
export const bulkhead = Effect.gen(function* () {
  const queue = yield* Queue.bounded<Job>(100);
  const sem = yield* Effect.makeSemaphore(4);

  const worker = Effect.forever(
    Effect.flatMap(Queue.take(queue), (j) => sem.withPermits(1)(handle(j))),
  );

  const fibers = yield* Effect.all([
    Effect.fork(worker),
    Effect.fork(worker),
    Effect.fork(worker),
    Effect.fork(worker),
  ]);
  return { queue, fibers } as const;
});
```

```typescript
import { Effect, Queue } from "effect";

declare const doWork: (n: number) => Effect.Effect<void>;

// The Queue's capacity back-pressures producers (offer blocks when full).
// The Semaphore caps parallel handlers even if many workers take concurrently.
export const program = Effect.gen(function* () {
  const q = yield* Queue.bounded<number>(32);
  const sem = yield* Effect.makeSemaphore(2);

  // One consumer fiber; the semaphore gates actual execution.
  yield* Effect.fork(
    Effect.forever(
      Effect.flatMap(Queue.take(q), (n) => sem.withPermits(1)(doWork(n))),
    ),
  );
  return q;
});
```

A bulkhead isolates a subsystem so that a surge in one area cannot drown the whole process. A bounded Queue alone gives back-pressure — producers wait when the queue is full — but if workers take faster than they can handle, you still get unbounded parallel handler execution. A Semaphore alone caps parallelism but does not back-pressure producers; they can allocate effects forever. Together: the Queue buffers and blocks producers, the Semaphore caps concurrent work.

