  const worker = Effect.forever(
    Effect.flatMap(Queue.take(q), (e) => sem.withPermits(1)(deliver(e))),
  );
  const fiber = yield* Effect.fork(worker);

  const offer = (e: Event) => Queue.offer(q, e);
  const shutdown = Effect.gen(function* () {
    // Drain: wait until size reaches 0, then shutdown the queue.
    yield* Effect.repeat(Queue.size(q), {
      until: (n: number) => n === 0,
    });
    yield* Queue.shutdown(q);
  });

  return { offer, shutdown, fiber } as const;
});
