import { Stream } from "effect";

declare const events: Stream.Stream<number>;

// Stream.debounce holds each value; a NEW value arriving within the window
// replaces the pending one. Only the last value in every burst is emitted.
export const debounced: Stream.Stream<number> = events.pipe(
  Stream.debounce("500 millis"),
);
```

Debounce collapses bursts: each new value resets a timer, and only the value that survives the quiet window is emitted. Throttle instead enforces a rate cap: values flow through but at most N per duration — excess are either dropped (enforce) or delayed (shape). Debounce fits user input; throttle fits rate-limiting against an API.

