import { Effect, Ref, Data, Clock } from "effect";

type State =
  | { readonly tag: "closed"; readonly fails: number }
  | { readonly tag: "open"; readonly until: number }
  | { readonly tag: "halfOpen" };

class BreakerOpen extends Data.TaggedError("BreakerOpen")<{}> {}

export const makeBreaker = <A, E>(
  work: Effect.Effect<A, E>,
  threshold = 3,
  cooldownMs = 1000,
) =>
  Effect.gen(function* () {
    const state = yield* Ref.make<State>({ tag: "closed", fails: 0 });
    const call: Effect.Effect<A, E | BreakerOpen> = Effect.gen(function* () {
      const now = yield* Clock.currentTimeMillis;
      const s = yield* Ref.get(state);
      if (s.tag === "open" && now < s.until) return yield* Effect.fail(new BreakerOpen());
      if (s.tag === "open") yield* Ref.set(state, { tag: "halfOpen" });
      return yield* Effect.tapBoth(work, {
        onFailure: () =>
          Ref.update(state, (cur): State =>
            cur.tag === "closed" && cur.fails + 1 >= threshold
              ? { tag: "open", until: now + cooldownMs }
              : cur.tag === "closed"
                ? { tag: "closed", fails: cur.fails + 1 }
                : { tag: "open", until: now + cooldownMs },
          ),
        onSuccess: () => Ref.set(state, { tag: "closed", fails: 0 }),
      });
    });
    return call;
  });
```

```typescript
import { Effect, Ref, Data, Clock } from "effect";

class Tripped extends Data.TaggedError("Tripped")<{}> {}

export const makeGate = <A, E>(work: Effect.Effect<A, E>, cooldownMs = 500) =>
  Effect.gen(function* () {
    const openUntil = yield* Ref.make<number>(0);
    const call: Effect.Effect<A, E | Tripped> = Effect.gen(function* () {
      const now = yield* Clock.currentTimeMillis;
      const until = yield* Ref.get(openUntil);
      if (now < until) return yield* Effect.fail(new Tripped());
      return yield* Effect.tapError(work, () =>
        Ref.set(openUntil, now + cooldownMs),
      );
    });
    return call;
  });
```

Closed is the happy path: calls flow through and failures increment a counter. When the counter crosses a threshold, the breaker trips to open — all calls fail fast for a cooldown window, giving the downstream time to recover. After cooldown the breaker goes half-open: it admits a single probe call. If the probe succeeds, the counter resets and we go back to closed; if it fails, we go straight back to open. Half-open exists so we don't blindly flood a recovering service with traffic.

```typescript
import { Effect, Ref, Data, Clock } from "effect";

type S =
  | { readonly t: "closed"; readonly n: number }
  | { readonly t: "open"; readonly until: number }
  | { readonly t: "half" };

class Open extends Data.TaggedError("Open")<{}> {}

export const makeBreaker = <A, E>(eff: Effect.Effect<A, E>, lim = 3, cd = 1000) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<S>({ t: "closed", n: 0 });
    return Effect.gen(function* () {
      const now = yield* Clock.currentTimeMillis;
      const s = yield* Ref.get(ref);
      if (s.t === "open" && now < s.until) return yield* Effect.fail(new Open());
      if (s.t === "open") yield* Ref.set(ref, { t: "half" });
      return yield* Effect.tapBoth(eff, {
        onSuccess: () => Ref.set(ref, { t: "closed", n: 0 }),
        onFailure: () =>
          Ref.update(ref, (c): S =>
            c.t === "closed" && c.n + 1 >= lim
              ? { t: "open", until: now + cd }
              : c.t === "closed"
                ? { t: "closed", n: c.n + 1 }
                : { t: "open", until: now + cd },
          ),
      }) as Effect.Effect<A, E | Open>;
    });
  });
```

