import { Effect, Ref, Data, Clock } from "effect";

type State =
  | { readonly tag: "closed"; readonly fails: number }
  | { readonly tag: "open"; readonly until: number };

class BreakerOpen extends Data.TaggedError("BreakerOpen")<{}> {}

export const wrapCircuit = <A, E>(
  eff: Effect.Effect<A, E>,
  threshold: number,
  cooldownMs: number,
): Effect.Effect<Effect.Effect<A, E | BreakerOpen>> =>
  Effect.map(Ref.make<State>({ tag: "closed", fails: 0 }), (ref) =>
    Effect.gen(function* () {
      const now = yield* Clock.currentTimeMillis;
      const s = yield* Ref.get(ref);
      if (s.tag === "open" && now < s.until)
        return yield* Effect.fail(new BreakerOpen());
      return yield* Effect.tapBoth(eff, {
        onSuccess: () => Ref.set(ref, { tag: "closed", fails: 0 }),
        onFailure: () =>
          Ref.update(ref, (c): State =>
            c.tag === "closed" && c.fails + 1 >= threshold
              ? { tag: "open", until: now + cooldownMs }
              : c.tag === "closed"
                ? { tag: "closed", fails: c.fails + 1 }
                : { tag: "open", until: now + cooldownMs },
          ),
      });
    }),
  );
