import { Effect, Cache, Duration, Data } from "effect";

interface User { readonly id: string; readonly name: string }
class HttpError extends Data.TaggedError("HttpError")<{ readonly status: number }> {}

declare const fetchUser: (id: string) => Effect.Effect<User, HttpError>;

// Cache.make returns Effect<Cache<K, V, E>> — lookups are typed end-to-end.
// Every call to `cache.get(id)` runs `fetchUser` on miss and caches for 10s.
export const makeUserCache: Effect.Effect<Cache.Cache<string, User, HttpError>> =
  Cache.make({
    capacity: 500,
    timeToLive: Duration.seconds(10),
    lookup: fetchUser,
  });

// Usage: the returned cache composes into any Effect pipeline.
export const lookupCached = (id: string) =>
  Effect.flatMap(makeUserCache, (c) => c.get(id));
