```typescript
import { Effect, Cache, Duration } from "effect";

declare const loadConfig: (key: string) => Effect.Effect<string>;

// Cache.make wraps the lookup; each `cache.get(key)` either returns a fresh
// cached value or runs the lookup and caches the result for 30s.
export const program = Effect.gen(function* () {
  const cache = yield* Cache.make({
    capacity: 128,
    timeToLive: Duration.seconds(30),
    lookup: loadConfig,
  });
  return yield* cache.get("feature.flags");
});
```

`timeToLive` is a per-entry expiry: after that Duration the cached value is considered stale and the next `get` re-runs the lookup. `capacity` is a hard upper bound on the number of live entries — if it is reached, the cache evicts least-recently-used entries before inserting a new one. They are independent: an entry can be evicted by capacity pressure before its TTL expires, and vice versa.

```typescript
import { Effect, Cache, Duration, Data } from "effect";

interface Row { readonly id: string; readonly name: string }
class DbError extends Data.TaggedError("DbError")<{ readonly msg: string }> {}
declare const loadRow: (id: string) => Effect.Effect<Row, DbError>;

export const program = Effect.gen(function* () {
  const cache = yield* Cache.make({
    capacity: 1_000,
    timeToLive: Duration.seconds(60),
    lookup: loadRow,
  });
  const a = yield* cache.get("42"); // miss → loadRow
  const b = yield* cache.get("42"); // hit → cached Row
  return [a, b] as const;
});
