import { Effect, Cache, Duration } from "effect";

export const makeTtlCache = <K, V, E>(
  capacity: number,
  ttl: Duration.Duration,
  lookup: (key: K) => Effect.Effect<V, E>,
): Effect.Effect<Cache.Cache<K, V, E>> =>
