  capacity: number,
  ttl: Duration.Duration,
  lookup: (key: K) => Effect.Effect<V, E>,
  key: K,
): Effect.Effect<V, E> =>
  Effect.flatMap(makeTtlCache(capacity, ttl, lookup), (c) => c.get(key));
