import { Effect, Cache, Duration } from "effect";

interface Price { readonly cents: number }
declare const fetchPrice: (sku: string) => Effect.Effect<Price>;

export const makePricingService = Effect.gen(function* () {
  const cache = yield* Cache.make({
    capacity: 1000,
    timeToLive: Duration.seconds(5),
    lookup: fetchPrice,
  });

  const get = (sku: string) => cache.get(sku);
  // refresh() invalidates the TTL for `sku` and runs the lookup again,
